Here's some sample code to get you started with creating your own Discord bot using Discord.js v14 and having one command called "ban". This code assumes you have already installed Discord.js and Node.js on your computer. 
First, create a new JavaScript file in your preferred editor or IDE (e.g., vscode, atom, sublime). Then, save it as `index.js` and run it in your terminal by navigating to the directory where the file is located and running `node index.js`.
```javascript
const { Client, Intents } = require('discord.js');
const client = new Client({ intents: [Intents.GUILDS] }); // Requires guilds intent to work
client.commands = new Map();
// Define the 'ban' command
client.commands.set('ban', {
    description: 'Bans a member from the server.',
    options: ['member'],
    guildId: 'guild-id',
    userId: 'user-id'
});
// Listen for messages
client.on('interactionCreate', interaction => {
    if (!interaction.isCommand()) return;

    const cmdName = interaction.commandName?.toLowerCase() ?? '';
    const cmdOptions = interaction.options?.map(o => o.name)?.join(', ');
    const cmdGuildId = interaction.guildId;
    const cmdUserId = interaction.userId;

    if (cmdName === 'ban') {
        const member = interaction.options.getMember(interaction.member);

        if (!member) {
            return interaction.reply({ content: 'Please mention the member you want to ban.', ephemeral: true });
        }

        if (!member.bannable) {
            return interaction.reply({ content: 'This member cannot be banned.', ephemeral: true });
        }

        member.kick('Ban by user').then(() => {
            interaction.reply(`${member.user} was successfully banned.`);
        }).catch((err) => {
            console.error(err);
            interaction.reply({ content: 'An error occurred while attempting to ban the member.', ephemeral: true });
        });
    }
});
// Start the bot
client.login(process.env.DISCORD_API_KEY);
```
